   146→	if err := unix.Mount(bpffsRoot, bpffsRoot, "bpf", 0, ""); err != nil {
   147→		return fmt.Errorf("failed to mount %s: %w", bpffsRoot, err)
   148→	}
   149→	return nil
   150→}
